//! phi3-pipeline-smoke — runs the WHOLE Phi-3 inference pipeline
//! end-to-end as a single native binary against a local `.knot` file.
//!
//! Mirrors `gemma4-pipeline-smoke.rs` and `native-pipeline-smoke.rs`
//! (the Qwen2 reference) but drives `model_phi3::Phi3Pipeline`. Used to
//! validate the Phi-3 kernel math + integration (fused QKV split,
//! NeoX RoPE, uniform 2048 SWA, SwiGLU FFN, tied lm_head) without
//! round-tripping through the trisplit CF Workers mesh or the
//! Cloud Run coordinator.
//!
//! ─── USAGE ───────────────────────────────────────────────────────────
//!
//! Canonical "France → Paris" smoke (uses the in-tree tokenizer
//! shortcut for the canonical prompt; no external tokenizer file
//! needed):
//!
//!   cargo run --release --bin phi3-pipeline-smoke -- \
//!     --knot /tmp/phi3-mini.knot \
//!     --prompt "Paris is the capital of"
//!
//! Direct token-id passthrough (for any other prompt; encode the IDs
//! upstream via `aether-tokenizer-bridge` or a one-off Python script):
//!
//!   cargo run --release --bin phi3-pipeline-smoke -- \
//!     --knot /tmp/phi3-mini.knot \
//!     --tokens 1,25719,338,278,7483,310
//!
//! Expected top-1 next token: `▁France` (id=3444). The smoke also
//! prints log-prob and top-10 so divergence is easy to bisect.
//!
//! ─── KNOT GAP ────────────────────────────────────────────────────────
//!
//! As of wave-23 there is no Phi-3 .knot on disk. The Phi-3 GGUF lives
//! at `/tmp/phi3-dl/Phi-3-mini-4k-instruct-Q4_K_M.gguf` (downloaded in
//! wave-19) but the encoder does not yet emit fused tensor names
//! (`blk_<L>_attn_qkv_weight`, fused gate/up under `blk_<L>_ffn_up_weight`)
//! so the conversion fails. `Phi3Pipeline::from_knot_with_kv_range`
//! surfaces this cleanly via `ENCODER_GAP` instead of panicking.
//!
//! Until the encoder lands, this binary BUILDS but cannot RUN against
//! a real .knot. That's the next ~30-min bule. See
//! `docs/phi-3-lm-head-tokenizer-smoke-result.md`.

use std::env;
use std::time::Instant;

use distributed_inference::loader::KnotWeights;
use distributed_inference::model_phi3::{
    phi3_tokenize_smoke_prompt, Phi3Pipeline, PHI3_FRANCE_TOKEN, PHI3_PARIS_PROMPT_TOKENS,
};

fn main() -> Result<(), String> {
    let args: Vec<String> = env::args().collect();
    let mut knot_path: Option<String> = None;
    let mut prompt: Option<String> = None;
    let mut tokens_csv: Option<String> = None;

    let mut i = 1;
    while i < args.len() {
        match args[i].as_str() {
            "--knot" => {
                i += 1;
                if i >= args.len() {
                    return Err("--knot requires a path argument".to_string());
                }
                knot_path = Some(args[i].clone());
            }
            "--prompt" => {
                i += 1;
                if i >= args.len() {
                    return Err("--prompt requires a string argument".to_string());
                }
                prompt = Some(args[i].clone());
            }
            "--tokens" => {
                i += 1;
                if i >= args.len() {
                    return Err("--tokens requires a comma-separated id list".to_string());
                }
                tokens_csv = Some(args[i].clone());
            }
            other => {
                return Err(format!(
                    "unknown arg: {}\nusage: {} --knot <path> [--prompt <string> | --tokens <id1,id2,...>]",
                    other, args[0]
                ))
            }
        }
        i += 1;
    }

    let knot_path = knot_path.ok_or_else(|| {
        format!(
            "missing --knot <path>\nusage: {} --knot <path> [--prompt <string> | --tokens <id1,id2,...>]",
            args.first().map(|s| s.as_str()).unwrap_or("phi3-pipeline-smoke")
        )
    })?;

    // Resolve token sequence: explicit --tokens wins, else --prompt
    // through the smoke tokenizer, else default to the canonical
    // "Paris is the capital of" prompt.
    let token_ids: Vec<u32> = if let Some(csv) = tokens_csv.as_ref() {
        csv.split(',')
            .map(|s| {
                s.trim()
                    .parse::<u32>()
                    .map_err(|e| format!("bad token {:?}: {}", s, e))
            })
            .collect::<Result<_, _>>()?
    } else if let Some(p) = prompt.as_ref() {
        phi3_tokenize_smoke_prompt(p).ok_or_else(|| {
            format!(
                "prompt {:?} not in the in-tree smoke tokenizer's table; \
                 use --tokens with explicit IDs or route through aether-tokenizer-bridge",
                p
            )
        })?
    } else {
        PHI3_PARIS_PROMPT_TOKENS.to_vec()
    };

    let t0 = Instant::now();
    println!("============================================================");
    println!(" phi3-pipeline-smoke");
    println!("   knot   : {}", knot_path);
    if let Some(p) = prompt.as_ref() {
        println!("   prompt : {:?}", p);
    }
    println!("   tokens : {:?}", token_ids);
    println!("============================================================");

    println!("[1/5] mmap knot");
    let t = Instant::now();
    let knot = KnotWeights::load(&knot_path).map_err(|e| format!("knot load: {:?}", e))?;
    println!("       ok ({} ms)", t.elapsed().as_millis());

    println!("[2/5] Phi3Pipeline::from_knot");
    let t = Instant::now();
    let mut pipeline = Phi3Pipeline::from_knot(knot)?;
    println!(
        "       ok ({} ms)  hidden={} layers={} heads={} kv_heads={} head_dim={} ffn={} vocab={} rope_theta={}",
        t.elapsed().as_millis(),
        pipeline.config.hidden_dim,
        pipeline.config.num_layers,
        pipeline.config.num_heads,
        pipeline.config.num_kv_heads,
        pipeline.config.head_dim,
        pipeline.config.intermediate_size,
        pipeline.config.vocab_size,
        pipeline.config.rope_theta,
    );

    println!("[3/5] forward {} prompt tokens", token_ids.len());
    let t = Instant::now();
    for (pos, &tok) in token_ids.iter().enumerate() {
        let lt = Instant::now();
        pipeline.forward_one(tok as usize, pos, false)?;
        println!(
            "       pos={:>2} tok={:>6}  {:>4} ms",
            pos,
            tok,
            lt.elapsed().as_millis()
        );
    }
    println!("       ok  total={} ms", t.elapsed().as_millis());

    // After the loop the LAST token's logits are sitting in pipeline.logits.
    let vocab_size = pipeline.config.vocab_size;
    let logits = &pipeline.logits[..vocab_size];
    let lo = logits.iter().cloned().fold(f32::INFINITY, f32::min);
    let hi = logits.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
    println!(
        "[4/5] logits  vocab={}  range=[{:.3}, {:.3}]",
        vocab_size, lo, hi
    );

    println!("[5/5] argmax + top-10 + log-prob");
    let mut idx: Vec<usize> = (0..vocab_size).collect();
    idx.sort_by(|&a, &b| {
        logits[b]
            .partial_cmp(&logits[a])
            .unwrap_or(std::cmp::Ordering::Equal)
    });
    let top1 = idx[0] as u32;
    // Compute log-softmax for the top1 (subtract max for numerical
    // stability, sum the exp tail).
    let max_logit = logits[idx[0]];
    let log_sum_exp: f32 = logits
        .iter()
        .map(|&l| (l - max_logit).exp())
        .sum::<f32>()
        .ln()
        + max_logit;
    let top1_logprob = logits[idx[0]] - log_sum_exp;
    println!("       top-10:");
    for &i in idx.iter().take(10) {
        let mark = if i as u32 == PHI3_FRANCE_TOKEN {
            "  <-- ▁France (expected)"
        } else {
            ""
        };
        println!(
            "         id={:6}  logit={:.4}  log_prob={:.4}{}",
            i,
            logits[i],
            logits[i] - log_sum_exp,
            mark
        );
    }
    println!(
        "       top-1: id={} logit={:.4} log_prob={:.4}",
        top1, logits[idx[0]], top1_logprob
    );

    let total = t0.elapsed().as_millis();
    if top1 == PHI3_FRANCE_TOKEN {
        println!(
            "\n[done] ✓ canonical Paris→France parity HOLDS  wall={} ms",
            total
        );
    } else {
        println!(
            "\n[done] phi3 pipeline ran end-to-end  wall={} ms  (top-1={} expected={})",
            total, top1, PHI3_FRANCE_TOKEN
        );
    }
    Ok(())
}
